import type {
  Experiment,
  ExperimentContext,
  Finding,
  ProbeResult,
  Verdict,
} from '../experiment-types.js';

interface AnthropicClaudeSonnet46LatencyExperimentEvidence extends Record<string, unknown> {
  model: string;
  samples: number;
  p50_latency_ms: number;
  mean_latency_ms: number;
  max_latency_ms: number;
  min_samples_required: number;
  warn_threshold_ms: number;
  fail_threshold_ms: number;
}

interface AnthropicClaudeSonnet46LatencyExperimentRow {
  latency_ms: number;
}

export class AnthropicClaudeSonnet46LatencyExperiment implements Experiment {
  id = 'anthropic-claude-sonnet-4-6-latency';
  name = 'Latency probe: anthropic/claude-sonnet-4.6';
  category = 'model_health' as const;
  hypothesis = 'anthropic/claude-sonnet-4.6 p50 latency stays below 54648ms on the rolling 50-call window.';
  cadence = { everyMs: 1800000, runOnBoot: false };

  async probe(ctx: ExperimentContext): Promise<ProbeResult> {
    const { data } = await ctx.db
      .from<AnthropicClaudeSonnet46LatencyExperimentRow>('llm_calls')
      .select('latency_ms')
      .eq('model', 'anthropic/claude-sonnet-4.6')
      .order('created_at', { ascending: false })
      .limit(50);

    const rows = (data ?? []) as AnthropicClaudeSonnet46LatencyExperimentRow[];
    const latencies = rows.map((r) => r.latency_ms).filter((v) => typeof v === 'number' && v >= 0);

    const samples = latencies.length;
    const sorted = [...latencies].sort((a, b) => a - b);
    const p50 = sorted.length > 0 ? sorted[Math.floor(sorted.length / 2)] : 0;
    const mean = latencies.length > 0 ? Math.round(latencies.reduce((a, b) => a + b, 0) / latencies.length) : 0;
    const max = latencies.length > 0 ? Math.max(...latencies) : 0;

    const evidence: AnthropicClaudeSonnet46LatencyExperimentEvidence = {
      model: 'anthropic/claude-sonnet-4.6',
      samples,
      p50_latency_ms: p50,
      mean_latency_ms: mean,
      max_latency_ms: max,
      min_samples_required: 10,
      warn_threshold_ms: 54648,
      fail_threshold_ms: 60134,
    };

    const summary =
      samples < 10
        ? `insufficient samples for ${'anthropic/claude-sonnet-4.6'}: ${samples} < ${10}`
        : `${'anthropic/claude-sonnet-4.6'}: p50 ${p50}ms over ${samples} calls (warn=54648, fail=60134)`;

    return {
      subject: `model:${'anthropic/claude-sonnet-4.6'}`,
      summary,
      evidence,
    };
  }

  judge(result: ProbeResult, _history: Finding[]): Verdict {
    const ev = result.evidence as AnthropicClaudeSonnet46LatencyExperimentEvidence;
    if (ev.samples < ev.min_samples_required) return 'warning';
    if (ev.p50_latency_ms >= ev.fail_threshold_ms) return 'fail';
    if (ev.p50_latency_ms >= ev.warn_threshold_ms) return 'warning';
    return 'pass';
  }
}
